  OUTPATIENT = 'Consulta Externa',
  EMERGENCY = 'Urgencias',
  HOSPITALIZATION = 'Hospitalización',
  AUXILIARY = 'Auxiliares',
  ADMIN = 'Gestión y Normatividad'
}

export enum PatientStatus {
  WAITING = 'En espera',
  IN_CONSULTATION = 'En consulta',
  ATTENDED = 'Atendido',
  TRIAGE = 'Triage'
}

