  status: PatientStatus;
  lastVisit: string;
  reason: string;
  chronicDiseases: string[];
}

export interface ClinicalNote {
  id: string;
  patientId: string;
  type: string;
  date: string;
  author: string;
  content: any;
  isSigned: boolean;
}

export interface TemperatureLog {
  id: string;
  timestamp: string;
  temperature: number;
  unit: string;
  responsible: string;
