import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate, Link, useLocation } from 'react-router-dom';
import { 
  Users, 
  Calendar, 
  Settings, 
  ShieldCheck, 
  LogOut, 
  Activity, 
  Stethoscope, 
  Clock,
  ClipboardList,
  AlertCircle
} from 'lucide-react';
import Dashboard from './views/Dashboard';
import PatientProfile from './views/PatientProfile';
import MedicalHistory from './views/MedicalHistory';
import AdminLogs from './views/AdminLogs';
import { ModuleType } from './types';

const Navbar = ({ currentModule, onModuleChange }: { currentModule: ModuleType, onModuleChange: (m: ModuleType) => void }) => {
  return (
    <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
      <div className="max-w-full px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center space-x-4">
            <div className="flex-shrink-0 flex items-center">
              <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center">
                <ShieldCheck className="text-white w-6 h-6" />
              </div>
              <span className="ml-3 text-xl font-bold text-slate-900 hidden md:block">MedExpediente <span className="text-blue-600">MX</span></span>
            </div>

            <div className="hidden md:flex ml-10 space-x-2">
              {Object.values(ModuleType).map((mod) => (
                <button
                  key={mod}
                  onClick={() => onModuleChange(mod)}
                  className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    currentModule === mod 
                    ? 'bg-blue-50 text-blue-700 border border-blue-100' 
                    : 'text-slate-600 hover:text-blue-600 hover:bg-slate-50'
                  }`}
                >
                  {mod}
                </button>
              ))}
            </div>
          </div>

          <div className="flex items-center space-x-4">
            <div className="flex flex-col items-end mr-2 hidden sm:flex">
              <span className="text-sm font-semibold text-slate-700">Dr. Alejandro Méndez</span>
              <span className="text-xs text-slate-500">Cédula: 12345678 (Vigente)</span>
            </div>
            <div className="flex items-center space-x-2 px-3 py-1 bg-green-50 rounded-full border border-green-200">
              <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
              <span className="text-xs font-medium text-green-700">Sesión Segura</span>
            </div>
            <button className="p-2 text-slate-400 hover:text-red-600 transition-colors">
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

const Sidebar = () => {
  const location = useLocation();
  const menuItems = [
    { icon: <Users className="w-5 h-5" />, label: 'Pacientes', path: '/' },
    { icon: <Calendar className="w-5 h-5" />, label: 'Agenda', path: '/agenda' },
    { icon: <ClipboardList className="w-5 h-5" />, label: 'Bitácoras', path: '/logs' },
    { icon: <Settings className="w-5 h-5" />, label: 'Ajustes', path: '/settings' },
  ];

  return (
    <aside className="w-20 lg:w-64 bg-white border-r border-slate-200 flex flex-col h-[calc(100vh-64px)] fixed left-0 top-16 overflow-y-auto">
      <div className="flex-1 py-6 space-y-1">
        {menuItems.map((item) => (
          <Link
            key={item.label}
            to={item.path}
            className={`flex items-center px-4 py-3 mx-2 rounded-lg transition-all ${
              location.pathname === item.path
              ? 'bg-blue-600 text-white shadow-md'
              : 'text-slate-500 hover:bg-slate-50 hover:text-blue-600'
            }`}
          >
            {item.icon}
            <span className="ml-3 font-medium hidden lg:block">{item.label}</span>
          </Link>
        ))}
      </div>
      <div className="p-4 border-t border-slate-100">
        <div className="bg-orange-50 p-3 rounded-lg border border-orange-100 hidden lg:block">
          <div className="flex items-start">
            <AlertCircle className="w-4 h-4 text-orange-600 mt-0.5" />
            <div className="ml-2">
              <p className="text-xs font-bold text-orange-800">NOM-004-SSA3</p>
              <p className="text-[10px] text-orange-700 leading-tight">Verificación de campos obligatorios activa.</p>
            </div>
          </div>
        </div>
      </div>
    </aside>
  );
};

const Layout = ({ children, currentModule, onModuleChange }: any) => (
  <div className="min-h-screen">
    <Navbar currentModule={currentModule} onModuleChange={onModuleChange} />
    <div className="flex">
      <Sidebar />
      <main className="flex-1 ml-20 lg:ml-64 p-4 lg:p-8 min-h-[calc(100vh-64px)]">
        {children}
      </main>
    </div>
  </div>
);

const App: React.FC = () => {
  const [currentModule, setCurrentModule] = useState<ModuleType>(ModuleType.OUTPATIENT);

  // Auto-inactivity closure logic simulation
  useEffect(() => {
    let timer: any;
    const resetTimer = () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        // console.log("Cierre por inactividad");
      }, 15 * 60 * 1000); // 15 mins
    };
    window.addEventListener('mousemove', resetTimer);
    return () => window.removeEventListener('mousemove', resetTimer);
  }, []);

  return (
    <Router>
      <Layout currentModule={currentModule} onModuleChange={setCurrentModule}>
        <Routes>
          <Route path="/" element={<Dashboard module={currentModule} />} />
          <Route path="/patient/:id" element={<PatientProfile />} />
          <Route path="/patient/:id/new-note" element={<MedicalHistory />} />
          <Route path="/logs" element={<AdminLogs />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

