// Changed MOCK_PATIENTS to INITIAL_PATIENTS to match exported member in constants.tsx
import { INITIAL_PATIENTS } from '../constants';

const MedicalHistory: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  // Changed MOCK_PATIENTS to INITIAL_PATIENTS
  const patient = INITIAL_PATIENTS.find(p => p.id === id);
  const [activeStep, setActiveStep] = useState(0);
  const [isSigning, setIsSigning] = useState(false);

  const steps = [
    { id: 0, label: 'Interrogatorio', icon: <User className="w-4 h-4" /> },
    { id: 1, label: 'Exploración Física', icon: <Stethoscope className="w-4 h-4" /> },
    { id: 2, label: 'Diagnóstico y Plan', icon: <Heart className="w-4 h-4" /> },
    { id: 3, label: 'Firma y Cierre', icon: <ShieldCheck className="w-4 h-4" /> }
  ];

  if (!patient) return null;

  const handleFinish = () => {
    // In a real app, send to backend then navigate back
    navigate(`/patient/${id}`);
  };

  return (
    <div className="max-w-5xl mx-auto pb-20">
      <div className="flex items-center justify-between mb-8">
