          </div>
          <button className="flex items-center px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 font-semibold transition-colors">
            <X className="w-4 h-4 mr-2" />
            Cancelar
          </button>
          <button 
            disabled={activeStep < 3}
            onClick={handleFinish}
