import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  Search, 
  ChevronRight,
  UserPlus,
  Clock,
  Users,
  PlayCircle,
  CheckCircle,
  Stethoscope
} from 'lucide-react';
import { ModuleType, Patient, PatientStatus } from '../types';

interface DashboardProps {
  module: ModuleType;
  patients: Patient[];
  onUpdateStatus: (id: string, status: PatientStatus) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ module, patients, onUpdateStatus }) => {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');

  // Remove patients already "Attended" from the dashboard to keep the active queue clear
  const filteredPatients = patients.filter(p => 
    p.assignedModule === module &&
    p.status !== PatientStatus.ATTENDED &&
    (p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.curp.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const getStatusColor = (status: PatientStatus) => {
    switch (status) {
      case PatientStatus.WAITING: return 'bg-amber-100 text-amber-700 border-amber-200';
      case PatientStatus.IN_CONSULTATION: return 'bg-blue-100 text-blue-700 border-blue-200';
      case PatientStatus.ATTENDED: return 'bg-green-100 text-green-700 border-green-200';
      case PatientStatus.TRIAGE: return 'bg-red-100 text-red-700 border-red-200';
      case PatientStatus.ADMITTED: return 'bg-purple-100 text-purple-700 border-purple-200';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">{module}</h1>
          <p className="text-slate-500 text-sm">Cola de atención activa • {filteredPatients.length} pacientes</p>
        </div>
        <button 
          onClick={() => navigate('/new-patient')}
          className="flex items-center px-6 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-all font-bold shadow-lg shadow-blue-100"
        >
          <UserPlus className="w-5 h-5 mr-2" />
          Ingresar Paciente
        </button>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
        <input 
          type="text" 
          placeholder="Buscar paciente en cola..."
          className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-100 outline-none transition-all shadow-sm text-slate-700"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        {filteredPatients.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200 text-slate-500 uppercase text-[10px] font-bold tracking-widest">
                  <th className="px-8 py-5">Paciente</th>
                  <th className="px-8 py-5">Motivo / Ingreso</th>
                  <th className="px-8 py-5">Estatus</th>
                  <th className="px-8 py-5 text-right">Acción Médica</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredPatients.map((p) => (
                  <tr key={p.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-8 py-5">
                      <div className="flex items-center">
                        <div className="w-12 h-12 rounded-2xl bg-slate-900 text-white flex items-center justify-center font-bold mr-4 shadow-sm group-hover:bg-blue-600 transition-colors">
                          {p.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors">{p.name}</p>
                          <p className="text-[10px] text-slate-400 font-mono tracking-tighter">{p.curp}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-5">
                      <p className="text-sm font-semibold text-slate-700">{p.reason}</p>
                      <div className="flex items-center mt-1 text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                        <Clock className="w-3 h-3 mr-1" />
                        {p.lastVisit}
                      </div>
                    </td>
                    <td className="px-8 py-5">
                      <span className={`px-3 py-1 rounded-xl text-[10px] font-bold border shadow-sm ${getStatusColor(p.status)}`}>
                        {p.status}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right">
                      <div className="flex items-center justify-end space-x-2">
                        {p.status === PatientStatus.WAITING || p.status === PatientStatus.TRIAGE ? (
                          <button 
                            onClick={() => onUpdateStatus(p.id, PatientStatus.IN_CONSULTATION)}
                            className="flex items-center px-4 py-2 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all text-xs font-bold border border-blue-100"
                          >
                            <PlayCircle className="w-4 h-4 mr-2" />
                            Atender
                          </button>
                        ) : p.status === PatientStatus.IN_CONSULTATION ? (
                          <button 
                            onClick={() => navigate(`/patient/${p.id}`)}
                            className="flex items-center px-4 py-2 bg-green-50 text-green-600 rounded-xl hover:bg-green-600 hover:text-white transition-all text-xs font-bold border border-green-100 shadow-sm"
                          >
                            <Stethoscope className="w-4 h-4 mr-2" />
                            Finalizar Atención
                          </button>
                        ) : (
                           <button 
                            onClick={() => navigate(`/patient/${p.id}`)}
                            className="p-2 bg-white border border-slate-200 text-slate-400 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm"
                          >
                            <ChevronRight className="w-5 h-5" />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="p-24 text-center">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6">
              <Users className="w-10 h-10 text-slate-200" />
