import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  Save, 
  X, 
  CheckCircle, 
  AlertCircle,
  FileText,
  User,
  Heart,
  Stethoscope,
  PenTool,
  ShieldCheck,
  ChevronLeft
} from 'lucide-react';
import { Patient, ClinicalNote } from '../types';

interface MedicalHistoryProps {
  patients: Patient[];
  onUpdatePatient: (p: Patient) => void;
  onSaveNote: (n: ClinicalNote) => void;
}

const MedicalHistory: React.FC<MedicalHistoryProps> = ({ patients, onUpdatePatient, onSaveNote }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const patient = patients.find(p => p.id === id);
  const [activeStep, setActiveStep] = useState(0);
  const [isSigning, setIsSigning] = useState(false);

  const [form, setForm] = useState({
    hereditary: patient?.history?.hereditary || '',
    pathological: patient?.history?.pathological || '',
    nonPathological: patient?.history?.nonPathological || '',
    physicalExam: '',
    diagnosis: '',
    plan: ''
  });

  const steps = [
    { id: 0, label: 'Antecedentes', icon: <User className="w-4 h-4" /> },
    { id: 1, label: 'Exploración Física', icon: <Stethoscope className="w-4 h-4" /> },
    { id: 2, label: 'Diagnóstico y Plan', icon: <Heart className="w-4 h-4" /> },
    { id: 3, label: 'Firma Electrónica', icon: <ShieldCheck className="w-4 h-4" /> }
  ];

  if (!patient) return <div className="p-20 text-center font-bold">Paciente no encontrado</div>;

  const handleFinish = () => {
    // 1. Update Patient Data
    const updatedPatient: Patient = {
      ...patient,
      history: {
        hereditary: form.hereditary,
        pathological: form.pathological,
        nonPathological: form.nonPathological
      }
    };
    onUpdatePatient(updatedPatient);

    // 2. Create Clinical Note
    const newNote: ClinicalNote = {
      id: `NOTE-HC-${Date.now()}`,
      patientId: patient.id,
      type: 'Historia Clínica',
      date: new Date().toLocaleString(),
      author: 'Dr. Alejandro Méndez',
      content: {
        subjective: `ANTECEDENTES: ${form.hereditary}. ${form.pathological}.`,
        objective: form.physicalExam,
        diagnosis: form.diagnosis,
        plan: form.plan
      },
      isSigned: true,
      hash: `SHA256-HC-${Math.random().toString(36).substr(2, 9).toUpperCase()}`
    };
    onSaveNote(newNote);

    navigate(`/patient/${id}`);
  };

  return (
    <div className="max-w-5xl mx-auto pb-20 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div className="flex items-center">
          <button onClick={() => navigate(-1)} className="mr-5 p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-all shadow-sm">
            <ChevronLeft className="w-6 h-6 text-slate-600" />
          </button>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Historia Clínica Integral</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] mt-1">NOM-004-SSA3-2012</p>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <button onClick={() => navigate(-1)} className="px-6 py-3 text-slate-500 font-bold text-sm">Cancelar</button>
          <button 
            disabled={activeStep < 3}
            onClick={handleFinish}
            className={`flex items-center px-8 py-3 rounded-2xl font-black text-sm shadow-xl transition-all ${activeStep === 3 ? 'bg-blue-600 text-white hover:bg-slate-900' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
          >
            <Save className="w-4 h-4 mr-2" />
            Guardar y Certificar
          </button>
        </div>
      </div>

      <div className="flex mb-10 bg-white border border-slate-200 rounded-3xl p-2 shadow-sm overflow-x-auto">
        {steps.map((step, idx) => (
          <button
            key={step.id}
            onClick={() => setActiveStep(idx)}
            className={`flex-1 min-w-[120px] flex items-center justify-center py-4 rounded-2xl transition-all ${
              activeStep === idx 
              ? 'bg-blue-600 text-white font-black shadow-lg shadow-blue-100' 
              : 'text-slate-400 hover:bg-slate-50'
            }`}
          >
            <span className="text-[10px] font-black uppercase tracking-widest">{step.label}</span>
          </button>
        ))}
      </div>

      <div className="bg-white border border-slate-200 rounded-[2.5rem] shadow-sm overflow-hidden">
        {activeStep === 0 && (
          <div className="p-10 space-y-10 animate-in slide-in-from-right-4 duration-300">
            <div className="space-y-6">
              <div>
                <label className="block text-[11px] font-black text-slate-400 uppercase mb-3">Antecedentes Heredofamiliares</label>
                <textarea className="w-full p-6 bg-slate-50 border border-slate-100 rounded-3xl h-32 text-sm font-medium" value={form.hereditary} onChange={e => setForm({...form, hereditary: e.target.value})} placeholder="Diabetes, HAS, Cáncer en línea directa..." />
              </div>
              <div>
                <label className="block text-[11px] font-black text-slate-400 uppercase mb-3">Personales Patológicos</label>
                <textarea className="w-full p-6 bg-slate-50 border border-slate-100 rounded-3xl h-32 text-sm font-medium" value={form.pathological} onChange={e => setForm({...form, pathological: e.target.value})} placeholder="Cirugías, fracturas, transfusiones..." />
              </div>
            </div>
            <div className="flex justify-end pt-6">
              <button onClick={() => setActiveStep(1)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-sm hover:bg-blue-600 transition-all">Siguiente: Exploración</button>
            </div>
          </div>
        )}

        {activeStep === 1 && (
          <div className="p-10 space-y-8 animate-in slide-in-from-right-4">
            <div>
              <label className="block text-[11px] font-black text-slate-400 uppercase mb-3">Exploración Física Segmentaria</label>
              <textarea className="w-full p-6 bg-slate-50 border border-slate-100 rounded-3xl h-64 text-sm font-medium" value={form.physicalExam} onChange={e => setForm({...form, physicalExam: e.target.value})} placeholder="Cabeza, cuello, tórax, abdomen, extremidades..." />
            </div>
            <div className="flex justify-between pt-6">
              <button onClick={() => setActiveStep(0)} className="px-10 py-4 text-slate-500 font-bold">Atrás</button>
              <button onClick={() => setActiveStep(2)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-sm">Siguiente: Diagnóstico</button>
            </div>
          </div>
        )}

        {activeStep === 2 && (
          <div className="p-10 space-y-8 animate-in slide-in-from-right-4">
            <div className="grid grid-cols-1 gap-6">
              <div>
                <label className="block text-[11px] font-black text-slate-400 uppercase mb-3">Diagnóstico Presuntivo / Definitivo</label>
                <input className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-black text-blue-700" value={form.diagnosis} onChange={e => setForm({...form, diagnosis: e.target.value})} />
              </div>
              <div>
                <label className="block text-[11px] font-black text-slate-400 uppercase mb-3">Plan Terapéutico Inicial</label>
                <textarea className="w-full p-6 bg-slate-50 border border-slate-100 rounded-3xl h-48 text-sm font-medium" value={form.plan} onChange={e => setForm({...form, plan: e.target.value})} />
              </div>
            </div>
            <div className="flex justify-between pt-6">
              <button onClick={() => setActiveStep(1)} className="px-10 py-4 text-slate-500 font-bold">Atrás</button>
              <button onClick={() => setActiveStep(3)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-sm">Siguiente: Firma</button>
            </div>
          </div>
        )}

        {activeStep === 3 && (
          <div className="p-12 text-center space-y-10">
            <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-600 mx-auto shadow-inner">
              <ShieldCheck className="w-12 h-12" />
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-900 uppercase">Certificación de Historia Clínica</h3>
              <p className="text-slate-500 text-sm mt-3 max-w-lg mx-auto leading-relaxed">
                Al guardar este documento, los antecedentes y hallazgos clínicos se vincularán de forma permanente al perfil del paciente para futuras consultas.
              </p>
            </div>
            <div className="w-full max-w-md mx-auto bg-slate-50 border-2 border-dashed border-slate-200 rounded-[2rem] p-10 cursor-pointer hover:border-blue-400 transition-all group" onClick={() => setIsSigning(true)}>
               {isSigning ? (
                 <div className="flex flex-col items-center">
                    <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                    <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest">Validando e.firma...</p>
                 </div>
               ) : (
                 <>
                   <PenTool className="w-10 h-10 text-slate-300 group-hover:text-blue-600 transition-all mb-4 mx-auto" />
                   <p className="text-slate-900 font-black text-xs uppercase tracking-widest">Haga clic para firmar</p>
                   <p className="text-[10px] text-slate-400 font-mono mt-1">HASH: HC-{Math.random().toString(16).substr(2,8).toUpperCase()}</p>
                 </>
               )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default MedicalHistory;

