import Telemedicine from './views/Telemedicine';
import Prescription from './views/Prescription';
import NewPatient from './views/NewPatient';
import Agenda from './views/Agenda';
import SettingsView from './views/Settings';
import DailyReport from './views/DailyReport';
import MedicalHistory from './views/MedicalHistory';
import { ModuleType, Patient, ClinicalNote, ConsultationRecord, PatientStatus } from './types';
import { INITIAL_PATIENTS } from './constants';

const App: React.FC = () => {
  const [currentModule, setCurrentModule] = useState<ModuleType>(ModuleType.OUTPATIENT);

  const [patients, setPatients] = useState<Patient[]>(() => {
    const saved = localStorage.getItem('med_patients_v4');
    return saved ? JSON.parse(saved) : INITIAL_PATIENTS;
  });

  const [notes, setNotes] = useState<ClinicalNote[]>(() => {
    const saved = localStorage.getItem('med_notes_v4');
    return saved ? JSON.parse(saved) : [];
  });

  const [consultations, setConsultations] = useState<ConsultationRecord[]>(() => {
    const saved = localStorage.getItem('med_consultations_v4');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('med_patients_v4', JSON.stringify(patients));
    localStorage.setItem('med_notes_v4', JSON.stringify(notes));
    localStorage.setItem('med_consultations_v4', JSON.stringify(consultations));
  }, [patients, notes, consultations]);

  const updatePatient = (updatedPatient: Patient) => {
    setPatients(prev => prev.map(p => p.id === updatedPatient.id ? updatedPatient : p));
  };

  const addPatient = (newPatient: Patient) => {
    setPatients(prev => [...prev, newPatient]);
  };

  const updatePatientStatus = (patientId: string, status: PatientStatus) => {
    setPatients(prev => prev.map(p => p.id === patientId ? { ...p, status } : p));
  };

  const addNote = (newNote: ClinicalNote) => {
    setNotes(prev => [newNote, ...prev]);

    const patient = patients.find(p => p.id === newNote.patientId);
    if (patient) {
      const record: ConsultationRecord = {
        id: `REC-${Date.now()}`,
        date: newNote.date,
        patientName: patient.name,
        curp: patient.curp,
        sex: patient.sex,
        age: patient.age,
        diagnosis: newNote.content.diagnosis || 'Sin Dx específico',
        treatment: newNote.content.plan || 'Revisar evolución en expediente',
        module: patient.assignedModule
      };
      setConsultations(prev => [record, ...prev]);
      updatePatientStatus(patient.id, PatientStatus.ATTENDED);
    }
  };

  return (
    <Router>
      <Layout currentModule={currentModule} onModuleChange={setCurrentModule}>
        <Routes>
          <Route path="/" element={<Dashboard module={currentModule} patients={patients} onUpdateStatus={updatePatientStatus} />} />
          <Route path="/new-patient" element={<NewPatient onAdd={addPatient} />} />
          <Route path="/patient/:id" element={<PatientProfile patients={patients} notes={notes} onUpdatePatient={updatePatient} />} />
          <Route path="/patient/:id/history" element={<MedicalHistory patients={patients} onUpdatePatient={updatePatient} onSaveNote={addNote} />} />
          <Route path="/patient/:id/new-note/:noteType" element={<NoteEditor onSave={addNote} />} />
          <Route path="/patient/:id/telemedicine" element={<Telemedicine />} />
          <Route path="/patient/:id/prescription" element={<Prescription patients={patients} />} />
          <Route path="/agenda" element={<Agenda onUpdateStatus={updatePatientStatus} patients={patients} />} />
          <Route path="/logs" element={<AdminLogs />} />
          <Route path="/daily-report" element={<DailyReport records={consultations} />} />
          <Route path="/settings" element={<SettingsView />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Layout>
    </Router>
  );
};

