import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  Search, 
  ChevronRight,
  UserPlus,
  Clock,
  Activity,
  ArrowRightCircle,
  Stethoscope,
  Filter,
  MoreVertical,
  MapPin,
  CalendarDays
} from 'lucide-react';
import { ModuleType, Patient, PatientStatus } from '../types';

interface DashboardProps {
  module: ModuleType;
  patients: Patient[];
  onUpdateStatus: (id: string, status: PatientStatus) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ module, patients, onUpdateStatus }) => {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');

  // Define status weights for sorting based on module urgency
  const statusWeights = useMemo(() => {
    const weights: Record<PatientStatus, number> = {
      [PatientStatus.TRIAGE]: 0,
      [PatientStatus.IN_CONSULTATION]: 1,
      [PatientStatus.WAITING]: 2,
      [PatientStatus.ADMITTED]: 3,
      [PatientStatus.ATTENDED]: 4,
    };
    return weights;
  }, []);

  const activePatients = useMemo(() => {
    return patients
      .filter(p => 
        p.assignedModule === module &&
        p.status !== PatientStatus.ATTENDED &&
        (p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.curp.toLowerCase().includes(searchTerm.toLowerCase()))
      )
      .sort((a, b) => statusWeights[a.status] - statusWeights[b.status]);
  }, [patients, module, searchTerm, statusWeights]);

  const getStatusStyle = (status: PatientStatus) => {
    switch (status) {
      case PatientStatus.WAITING: return 'bg-amber-50 text-amber-700 border-amber-200';
      case PatientStatus.IN_CONSULTATION: return 'bg-blue-50 text-blue-700 border-blue-200';
      case PatientStatus.TRIAGE: return 'bg-rose-50 text-rose-700 border-rose-200 animate-pulse';
      case PatientStatus.ADMITTED: return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      default: return 'bg-slate-50 text-slate-600 border-slate-200';
    }
  };

  const getModuleIcon = () => {
    switch(module) {
      case ModuleType.EMERGENCY: return <Activity className="w-5 h-5 text-rose-600" />;
      case ModuleType.HOSPITALIZATION: return <MapPin className="w-5 h-5 text-indigo-600" />;
      default: return <Clock className="w-5 h-5 text-blue-600" />;
    }
  };

  const getSecondaryColHeader = () => {
    if (module === ModuleType.OUTPATIENT) return "Cita / Horario";
    if (module === ModuleType.EMERGENCY || module === ModuleType.HOSPITALIZATION) return "Ubicación / Cama";
    return "Referencia";
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in fade-in duration-500">
      {/* Header Bar */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div className="space-y-1">
          <div className="flex items-center space-x-2 text-slate-400 uppercase text-[10px] font-bold tracking-[0.2em]">
            {getModuleIcon()}
            <span>Módulo Operativo Activo</span>
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">{module}</h1>
          <p className="text-slate-500 text-sm font-medium">Hay <span className="text-blue-600 font-bold">{activePatients.length} pacientes</span> en cola de atención priorizada.</p>
        </div>
        <div className="flex items-center space-x-3">
          <button className="p-2.5 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-slate-900 transition-colors shadow-sm">
            <Filter className="w-5 h-5" />
          </button>
          <button 
            onClick={() => navigate('/new-patient')}
            className="flex items-center px-6 py-3 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 transition-all font-bold shadow-lg shadow-blue-100"
          >
            <UserPlus className="w-5 h-5 mr-2" />
            Nuevo Registro
          </button>
        </div>
      </div>

      {/* Search & Actions */}
      <div className="bg-white p-2 rounded-3xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-2">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por Nombre, CURP o Expediente..."
            className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border border-transparent rounded-2xl focus:bg-white focus:border-blue-200 outline-none transition-all text-sm font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100 text-slate-400 uppercase text-[10px] font-bold tracking-widest">
                <th className="px-8 py-5">Identificación Paciente</th>
                <th className="px-8 py-5">{getSecondaryColHeader()}</th>
                <th className="px-8 py-5">Estatus Actual</th>
                <th className="px-8 py-5 text-right">Acciones Clínicas</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {activePatients.map((p) => (
                <tr key={p.id} className="hover:bg-blue-50/30 transition-all group">
                  <td className="px-8 py-5">
                    <div className="flex items-center">
                      <div className="w-11 h-11 rounded-xl bg-slate-100 text-slate-900 flex items-center justify-center font-bold mr-4 border border-slate-200 group-hover:bg-blue-600 group-hover:text-white group-hover:border-blue-500 transition-all">
                        {p.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-900 tracking-tight">{p.name}</p>
                        <div className="flex items-center space-x-2 mt-0.5">
                           <span className="text-[10px] text-slate-400 font-mono">{p.curp}</span>
                           <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                           <span className="text-[10px] text-slate-500 font-bold uppercase">{p.age} años • {p.sex}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-5">
                    {module === ModuleType.OUTPATIENT ? (
                      <div className="space-y-1">
                        <div className="flex items-center text-xs font-bold text-blue-700">
                          <Clock className="w-3.5 h-3.5 mr-1.5" />
                          {p.appointmentTime || '--:--'}
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase truncate max-w-[150px]">{p.reason}</p>
                      </div>
                    ) : (
                      <div className="space-y-1">
                        <div className="flex items-center text-xs font-bold text-indigo-700">
                          <MapPin className="w-3.5 h-3.5 mr-1.5" />
                          {p.bedNumber || 'Sin Asignar'}
                        </div>
                        <div className="flex items-center text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                          <Clock className="w-3 h-3 mr-1.5" />
                          {p.lastVisit}
                        </div>
                      </div>
                    )}
                  </td>
                  <td className="px-8 py-5">
                    <span className={`inline-flex items-center px-3 py-1 rounded-lg text-[10px] font-bold border ${getStatusStyle(p.status)}`}>
                      <span className={`w-1.5 h-1.5 rounded-full mr-2 ${p.status === PatientStatus.TRIAGE ? 'bg-rose-500 animate-pulse' : 'bg-current'}`}></span>
                      {p.status}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-right">
                    <div className="flex items-center justify-end space-x-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      {p.status === PatientStatus.WAITING || p.status === PatientStatus.TRIAGE ? (
                        <button 
                          onClick={() => onUpdateStatus(p.id, PatientStatus.IN_CONSULTATION)}
                          className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-xl hover:bg-slate-900 transition-all text-xs font-bold shadow-md shadow-blue-100"
                        >
                          <Stethoscope className="w-3.5 h-3.5 mr-2" />
                          Iniciar Atención
                        </button>
                      ) : (
                        <button 
                          onClick={() => navigate(`/patient/${p.id}`)}
                          className="flex items-center px-4 py-2 bg-slate-900 text-white rounded-xl hover:bg-blue-600 transition-all text-xs font-bold"
                        >
                          Abrir Expediente
                          <ArrowRightCircle className="w-3.5 h-3.5 ml-2" />
                        </button>
                      )}
                      <button className="p-2 text-slate-400 hover:text-slate-900">
                         <MoreVertical className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {activePatients.length === 0 && (
                <tr>
                   <td colSpan={4} className="py-24 text-center">
                      <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 border border-slate-200">
                         <Activity className="w-10 h-10 text-slate-300" />
                      </div>
                      <p className="text-slate-900 font-bold">Sin pacientes en cola para {module}</p>
                      <p className="text-sm text-slate-400 mt-1">Todos los servicios programados han sido completados.</p>
                   </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

