import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Search, UserPlus, Clock, Activity, ArrowRightCircle, Stethoscope, Filter, MapPin, AlertCircle } from 'lucide-react';
import { ModuleType, Patient, PatientStatus } from '../types';

interface DashboardProps {
  module: ModuleType;
  patients: Patient[];
  onUpdateStatus: (id: string, status: PatientStatus) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ module, patients, onUpdateStatus }) => {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');

  const activePatients = useMemo(() => {
    return patients
      .filter(p => p.assignedModule === module && p.status !== PatientStatus.ATTENDED)
      .filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.curp.toLowerCase().includes(searchTerm.toLowerCase()))
      .sort((a, b) => {
        const priority: Record<string, number> = { [PatientStatus.TRIAGE]: 0, [PatientStatus.IN_CONSULTATION]: 1, [PatientStatus.WAITING]: 2, [PatientStatus.ADMITTED]: 3 };
        return (priority[a.status] ?? 9) - (priority[b.status] ?? 9);
      });
  }, [patients, module, searchTerm]);

  const getStatusStyle = (status: PatientStatus) => {
    switch (status) {
      case PatientStatus.TRIAGE: return 'bg-rose-50 text-rose-700 border-rose-200 animate-pulse';
      case PatientStatus.IN_CONSULTATION: return 'bg-blue-50 text-blue-700 border-blue-200';
      case PatientStatus.ADMITTED: return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      default: return 'bg-slate-50 text-slate-600 border-slate-200';
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <div className="flex items-center space-x-2 text-slate-400 uppercase text-[10px] font-black tracking-[0.2em]">
            <Activity className="w-3.5 h-3.5" />
            <span>Módulo Clínico Activo</span>
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight uppercase">{module}</h1>
          <p className="text-slate-500 text-sm font-medium">Gestión de pacientes en {module.toLowerCase()}.</p>
        </div>
        <div className="flex items-center space-x-3">
          <button className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-400 hover:text-slate-900 shadow-sm transition-all"><Filter className="w-5 h-5" /></button>
          <button onClick={() => navigate('/new-patient')} className="flex items-center px-8 py-3 bg-blue-600 text-white rounded-2xl font-black shadow-xl shadow-blue-100 hover:bg-slate-900 transition-all active:scale-95">
            <UserPlus className="w-5 h-5 mr-3" /> Ingresar Paciente
          </button>
        </div>
      </div>

      <div className="bg-white p-2 rounded-[2rem] shadow-sm border border-slate-200 flex flex-col md:flex-row gap-2">
        <div className="relative flex-1">
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por Nombre o CURP..."
            className="w-full pl-14 pr-6 py-4 bg-slate-50 border border-transparent rounded-2xl focus:bg-white focus:border-blue-200 outline-none transition-all text-sm font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50/50 border-b border-slate-100 text-[9px] font-black text-slate-400 uppercase tracking-widest">
            <tr>
              <th className="px-10 py-6">Identificación</th>
              <th className="px-10 py-6">Referencia / Cama</th>
              <th className="px-10 py-6">Estatus</th>
              <th className="px-10 py-6 text-right">Manejo</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {activePatients.map((p) => (
              <tr key={p.id} className="hover:bg-blue-50/30 transition-all group">
                <td className="px-10 py-6">
                  <div className="flex items-center">
                    <div className="w-12 h-12 rounded-2xl bg-slate-900 text-white flex items-center justify-center font-black mr-5 border-2 border-white shadow-md group-hover:bg-blue-600 transition-colors">{p.name.charAt(0)}</div>
                    <div>
                      <p className="font-black text-slate-900 text-sm tracking-tight uppercase">{p.name}</p>
                      <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">{p.age}A • {p.sex} • {p.curp}</p>
                    </div>
                  </div>
                </td>
                <td className="px-10 py-6">
                  {module === ModuleType.OUTPATIENT ? (
                    <div className="flex items-center text-xs font-black text-slate-600"><Clock className="w-4 h-4 mr-2.5 text-blue-600" /> {p.appointmentTime || 'PENDIENTE'}</div>
                  ) : (
                    <div className="flex items-center text-xs font-black text-slate-600"><MapPin className="w-4 h-4 mr-2.5 text-indigo-600" /> {p.bedNumber || 'BOX ATENCIÓN'}</div>
                  )}
                </td>
                <td className="px-10 py-6">
                  <span className={`inline-flex items-center px-4 py-1.5 rounded-xl text-[9px] font-black border uppercase tracking-widest ${getStatusStyle(p.status)}`}>
                    <span className={`w-1.5 h-1.5 rounded-full mr-2.5 ${p.status === PatientStatus.TRIAGE ? 'bg-rose-500 animate-pulse' : 'bg-current'}`}></span>
                    {p.status}
                  </span>
                </td>
                <td className="px-10 py-6 text-right">
                  <button onClick={() => navigate(`/patient/${p.id}`)} className="px-5 py-2.5 bg-slate-900 text-white rounded-xl hover:bg-blue-600 transition-all text-[10px] font-black uppercase tracking-widest shadow-lg">
                    Ver Expediente <ArrowRightCircle className="w-4 h-4 ml-2.5" />
                  </button>
                </td>
              </tr>
            ))}
            {activePatients.length === 0 && (
              <tr><td colSpan={4} className="py-32 text-center text-slate-300 font-bold uppercase tracking-widest">Sin pacientes registrados en {module}</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

