             <p className="text-[10px] text-slate-500 font-medium leading-relaxed uppercase">Expediente resguardado bajo la NOM-004-SSA3-2012 y la LFPDPPP.</p>
          </div>
        </div>
      </div>

      {/* FAB y Menú Actos Médicos */}
      <div className="fixed bottom-10 right-10 z-[90]">
        <button onClick={() => setShowMenu(true)} className="w-20 h-20 rounded-[2rem] flex items-center justify-center text-white shadow-2xl bg-blue-600 hover:bg-slate-900 transition-all hover:rotate-90 active:scale-90"><Plus className="w-10 h-10" /></button>
      </div>

      {showMenu && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white w-full max-w-4xl max-h-[85vh] rounded-[3rem] shadow-2xl overflow-hidden flex flex-col">
            <div className="p-8 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
              <div><h4 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Catálogo de Actos Médicos NOM-004</h4><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Seleccione el tipo de nota a generar</p></div>
              <button onClick={() => setShowMenu(false)} className="p-2 hover:bg-white rounded-xl transition-all shadow-sm border border-transparent hover:border-slate-300"><X className="w-6 h-6 text-slate-600" /></button>
            </div>
            <div className="p-10 overflow-y-auto grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {NOTE_CATEGORIES.map(cat => (
                <div key={cat.title}>
                  <p className="text-[10px] font-black text-blue-700 uppercase tracking-[0.2em] mb-4 flex items-center"><span className="w-2 h-2 bg-blue-700 rounded-full mr-3"></span>{cat.title}</p>
                  <div className="space-y-2">
                    {cat.notes.map(note => (
                      <button key={note} onClick={() => navigate(`/patient/${id}/new-note/${encodeURIComponent(note)}`)} className="w-full text-left p-4 bg-slate-50 border border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-800 hover:bg-blue-600 hover:text-white transition-all flex items-center justify-between group shadow-sm">
                        {note} <ChevronRight className="w-4 h-4 opacity-0 group-hover:opacity-100 transition-all" />
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Modal Signos Vitales */}
      {showVitalsModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl p-12">
            <div className="flex justify-between items-center mb-10"><h4 className="text-2xl font-black text-slate-900 uppercase">Actualizar Somatometría</h4><button onClick={() => setShowVitalsModal(false)} className="p-2 hover:bg-slate-100 rounded-xl transition-all"><X className="w-7 h-7 text-slate-600" /></button></div>
            <div className="grid grid-cols-2 gap-8 mb-12">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">P. Arterial</label><input type="text" className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-black text-slate-900 outline-none focus:ring-4 focus:ring-blue-100 transition-all" value={vitalsForm.bp} onChange={e => setVitalsForm({...vitalsForm, bp: e.target.value})} /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Temperatura</label><input type="number" step="0.1" className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-black text-slate-900 outline-none focus:ring-4 focus:ring-blue-100 transition-all" value={vitalsForm.temp} onChange={e => setVitalsForm({...vitalsForm, temp: parseFloat(e.target.value)})} /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Peso (kg)</label><input type="number" step="0.1" className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-black text-slate-900 outline-none focus:ring-4 focus:ring-blue-100 transition-all" value={vitalsForm.weight} onChange={e => setVitalsForm({...vitalsForm, weight: parseFloat(e.target.value)})} /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Talla (cm)</label><input type="number" className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-black text-slate-900 outline-none focus:ring-4 focus:ring-blue-100 transition-all" value={vitalsForm.height} onChange={e => setVitalsForm({...vitalsForm, height: parseInt(e.target.value)})} /></div>
            </div>
            <button onClick={handleUpdateVitals} className="w-full py-5 bg-blue-600 text-white rounded-3xl font-black uppercase shadow-2xl shadow-blue-200 hover:bg-slate-900 transition-all">Guardar Registro Histórico</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default PatientProfile;

import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  ChevronLeft, 
  Save, 
  X, 
  ShieldCheck, 
  PenTool, 
  AlertCircle, 
  CheckCircle2,
  Stethoscope,
  Activity,
  AlertTriangle
} from 'lucide-react';
import { ClinicalNote } from '../types';

interface NoteEditorProps {
  onSave: (note: ClinicalNote) => void;
}

const NoteEditor: React.FC<NoteEditorProps> = ({ onSave }) => {
  const { id, noteType } = useParams();
  const navigate = useNavigate();
  const type = decodeURIComponent(noteType || '');

  const [formData, setFormData] = useState({
    subjective: '',
    objective: '',
    analysis: '',
    plan: '',
    diagnosis: '',
    observations: '',
    triageLevel: 'Verde',
    prognosis: 'Reservado a evolución'
  });

  const [isSigning, setIsSigning] = useState(false);
  const [signatureDone, setSignatureDone] = useState(false);

  const isEmergencyNote = type.toLowerCase().includes('urgencias');

  const handleSave = () => {
    if (!formData.diagnosis || !formData.subjective) {
        alert("Campos Críticos: 'Subjetivo' y 'Diagnóstico' son requeridos por la NOM-004.");
        return;
    }

    if (!signatureDone) {
        setIsSigning(true);
        return;
    }

    const newNote: ClinicalNote = {
      id: `NOTE-${Date.now()}`,
      patientId: id || '',
      type: type,
      date: new Date().toLocaleString('es-MX', { dateStyle: 'long', timeStyle: 'short' }),
      author: 'Dr. Alejandro Méndez',
      content: formData,
      isSigned: true,
      hash: `SHA256-${Math.random().toString(36).substr(2, 12).toUpperCase()}`
    };
    onSave(newNote);
    navigate(`/patient/${id}`);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-20">
      {/* Dynamic Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center">
          <button onClick={() => navigate(-1)} className="mr-5 p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 shadow-sm transition-all group hover:border-slate-300">
            <ChevronLeft className="w-6 h-6 text-slate-700 group-hover:-translate-x-1 transition-transform" />
          </button>
          <div>
            <div className="flex items-center space-x-2 text-slate-500 uppercase text-[10px] font-black tracking-[0.2em] mb-1">
              <Activity className="w-3.5 h-3.5" />
              <span>Acto Médico Certificado</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight uppercase">{type}</h1>
          </div>
        </div>
        <div className="flex gap-3">
          <button onClick={() => navigate(-1)} className="px-6 py-3 text-slate-600 text-sm font-bold flex items-center hover:text-slate-900 transition-colors">
            <X className="w-4 h-4 mr-2" /> Descartar
          </button>
          <button 
            onClick={handleSave}
            className="px-8 py-3 bg-blue-600 text-white rounded-2xl font-black shadow-xl shadow-blue-100 hover:bg-slate-900 transition-all flex items-center active:scale-95"
          >
            <ShieldCheck className="w-4 h-4 mr-2.5" /> 
            {signatureDone ? 'Guardar Definitivo' : 'Certificar con e.firma'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
           {/* Triage Info for Emergency */}
           {isEmergencyNote && (
             <div className="bg-rose-50 border border-rose-200 rounded-[2rem] p-6 flex items-center justify-between">
                <div className="flex items-center">
                   <AlertTriangle className="w-8 h-8 text-rose-700 mr-4" />
                   <div>
                      <p className="text-[10px] font-black text-rose-800 uppercase tracking-widest">Nivel de Triage</p>
                      <p className="text-sm font-bold text-rose-900 uppercase">Urgencia Calificada</p>
                   </div>
                </div>
                <select 
                  className="bg-white border border-rose-300 rounded-xl px-4 py-2 text-xs font-black outline-none text-slate-900"
                  value={formData.triageLevel}
                  onChange={e => setFormData({...formData, triageLevel: e.target.value})}
                >
                  <option value="Rojo">Rojo (Inmediato)</option>
                  <option value="Naranja">Naranja (10 min)</option>
                  <option value="Amarillo">Amarillo (30-60 min)</option>
                  <option value="Verde">Verde (Sin urgencia)</option>
                </select>
             </div>
           )}

           <div className="bg-white border border-slate-200 rounded-[2.5rem] p-10 space-y-10 shadow-sm relative overflow-hidden">
              <div className="absolute top-0 right-0 p-10 opacity-[0.03] pointer-events-none">
                 <Stethoscope className="w-64 h-64" />
              </div>

              <div className="space-y-8 relative z-10">
                {/* SOAP Structure */}
                <div>
                  <div className="flex items-center justify-between mb-4">
                     <label className="text-[11px] font-black text-slate-600 uppercase tracking-widest flex items-center">
                        Subjetivo (Padecimiento Actual) <span className="text-rose-600 ml-1">*</span>
                     </label>
                  </div>
                  <textarea 
                    className="w-full p-6 bg-slate-50 border border-slate-200 rounded-[2rem] h-48 outline-none focus:bg-white focus:ring-4 focus:ring-blue-100 transition-all text-sm font-medium text-slate-900 placeholder:text-slate-400 leading-relaxed shadow-inner"
                    value={formData.subjective}
                    onChange={e => setFormData({...formData, subjective: e.target.value})}
                    placeholder="Antecedentes, interrogatorio por aparatos y sistemas, síntomas reportados..."
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div>
                    <label className="block text-[11px] font-black text-slate-600 uppercase tracking-widest mb-4">Diagnóstico (CIE-10) <span className="text-rose-600">*</span></label>
                    <input 
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:bg-white focus:ring-4 focus:ring-blue-100 transition-all text-sm font-black text-blue-700 shadow-inner"
                      value={formData.diagnosis}
                      onChange={e => setFormData({...formData, diagnosis: e.target.value})}
                      placeholder="Ej: J03.9 Faringitis aguda..."
                    />
                  </div>
                  <div>
                    <label className="block text-[11px] font-black text-slate-600 uppercase tracking-widest mb-4">Exploración Física</label>
                    <input 
                      className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:bg-white focus:ring-4 focus:ring-blue-100 transition-all text-sm font-medium text-slate-900 shadow-inner"
                      value={formData.objective}
                      onChange={e => setFormData({...formData, objective: e.target.value})}
                      placeholder="Signos vitales, exploración segmentaria..."
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-[11px] font-black text-slate-600 uppercase tracking-widest mb-4">Pronóstico para la Vida y Función</label>
                  <input 
                    className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:bg-white focus:ring-4 focus:ring-blue-100 transition-all text-sm font-bold text-slate-800 shadow-inner"
                    value={formData.prognosis}
                    onChange={e => setFormData({...formData, prognosis: e.target.value})}
                  />
                </div>

                <div>
                  <label className="block text-[11px] font-black text-slate-600 uppercase tracking-widest mb-4">Plan Terapéutico e Indicaciones</label>
                  <textarea 
                    className="w-full p-6 bg-slate-50 border border-slate-200 rounded-[2rem] h-48 outline-none focus:bg-white focus:ring-4 focus:ring-blue-100 transition-all text-sm font-medium text-slate-900 leading-relaxed shadow-inner placeholder:text-slate-400"
                    value={formData.plan}
                    onChange={e => setFormData({...formData, plan: e.target.value})}
                    placeholder="Instrucciones detalladas de manejo clínico..."
                  />
                </div>
              </div>
           </div>
        </div>

        <div className="space-y-6">
           <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden group">
              <div className="absolute -right-4 -bottom-4 p-8 opacity-5 group-hover:scale-110 transition-transform">
                 <ShieldCheck className="w-32 h-32" />
              </div>
              <h3 className="text-lg font-bold mb-6 flex items-center">
                 <AlertCircle className="w-5 h-5 mr-3 text-blue-400" /> Auditoría NOM-004
              </h3>
              <ul className="space-y-4">
                 {[
                   'Obligatorio: Firma manuscrita o electrónica.',
                   'Integridad: El documento no permite tachaduras.',
                   'Conservación: Mínimo 5 años en archivo.',
                   'Propiedad: Pertenece a la Institución Médica.'
                 ].map((text, i) => (
                   <li key={i} className="flex items-start text-xs text-slate-300 font-medium">
                      <div className="w-1.5 h-1.5 bg-blue-500 rounded-full mt-1.5 mr-3 flex-shrink-0"></div>
                      {text}
                   </li>
                 ))}
              </ul>
           </div>

           <div className={`p-10 rounded-[2.5rem] border-2 border-dashed transition-all text-center ${signatureDone ? 'bg-emerald-50 border-emerald-500' : 'bg-white border-slate-300'}`}>
              <PenTool className={`w-12 h-12 mx-auto mb-4 ${signatureDone ? 'text-emerald-700' : 'text-slate-300'}`} />
              <p className="text-sm font-black text-slate-900 uppercase">Validación de Firma</p>
              <p className={`text-[10px] font-black uppercase tracking-widest mt-1 ${signatureDone ? 'text-emerald-700' : 'text-slate-500'}`}>
                 {signatureDone ? 'AUTENTICADO CON E.FIRMA' : 'REQUERIDO PARA GUARDAR'}
              </p>
           </div>
        </div>
      </div>

      {/* Signature Overlay */}
      {isSigning && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white rounded-[3.5rem] p-12 max-w-lg w-full text-center space-y-8 shadow-2xl">
              <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center mx-auto shadow-inner">
                 <ShieldCheck className="w-12 h-12 text-blue-600" />
              </div>
              <div>
                 <h2 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Confirmar Acto Médico</h2>
                 <p className="text-slate-600 text-sm mt-4 px-6 font-medium leading-relaxed uppercase">
                    Al certificar, este documento se integrará de forma inmutable al expediente clínico bajo la <span className="text-blue-700 font-bold">NOM-004-SSA3-2012</span>.
                 </p>
              </div>
              <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 text-left flex items-center">
                 <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center shadow-sm mr-4 border border-slate-100">
                    <PenTool className="text-blue-700 w-6 h-6" />
                 </div>
                 <div>
                    <p className="text-xs font-black text-slate-900 uppercase">Dr. Alejandro Méndez</p>
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-tighter">CED. PROF: 12345678</p>
                 </div>
              </div>
              <div className="flex gap-4">
                 <button onClick={() => setIsSigning(false)} className="flex-1 py-4 text-slate-500 font-black text-sm hover:text-slate-900 transition-colors uppercase tracking-widest">Cancelar</button>
                 <button 
                  onClick={() => {
                    setSignatureDone(true);
                    setIsSigning(false);
                  }} 
                  className="flex-1 py-4 bg-slate-900 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-600 transition-all active:scale-95 uppercase tracking-widest"
                 >
                    Certificar Documento
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default NoteEditor;
